R = ZZ['x']
x = R.gen()

# Build quotient rings properly
Rq = PolynomialRing(GF(q), names=('xq',)); (xq,) = Rq._first_ngens(1)
Rp = PolynomialRing(GF(p), names=('xp',)); (xp,) = Rp._first_ngens(1)

def poly_from_vec(v):
    return sum(v[i]*x**i for i in range(len(v))) % (x**N - _sage_const_1 )

def center_lift(poly, q):
    coeffs = poly.list()
    # Pad to length N
    coeffs += [_sage_const_0 ] * (N - len(coeffs))
    lifted = []
    for c in coeffs:
        c = ZZ(c) % q
        if c > q // _sage_const_2 :
            c -= q
        lifted.append(c)
    return sum(lifted[i]*x**i for i in range(N)) % (x**N - _sage_const_1 )

def is_invertible(f_coeffs, Ring, modpoly):
    try:
        f_r = Ring(f_coeffs)
        f_r.inverse_mod(modpoly)
        return True
    except:
        return False

def find_fg(vectors):
    """
    Try all vectors as candidate f; look for one invertible mod p and q.
    g is reconstructed from the second half.
    """
    for v in vectors:
        if len(v) != _sage_const_2  * N:
            continue
        
        f_vec = list(v[:N])
        g_vec = list(v[N:])
        
        # Check small coefficients (NTRU keys are in {-1,0,1})
        if max(abs(c) for c in f_vec) > _sage_const_3 :
            continue
        if max(abs(c) for c in g_vec) > _sage_const_3 :
            continue
        
        f_coeffs_q = [GF(q)(c) for c in f_vec]
        f_coeffs_p = [GF(p)(c) for c in f_vec]
        
        # Check invertibility in both rings
        try:
            fq = Rq(f_coeffs_q)
            fq.inverse_mod(xq**N - _sage_const_1 )
        except:
            continue
        try:
            fp = Rp(f_coeffs_p)
            fp.inverse_mod(xp**N - _sage_const_1 )
        except:
            continue
        
        print(f"Found valid f: {f_vec}")
        print(f"Corresponding g: {g_vec}")
        return f_vec, g_vec
    
    return None, None

# Read ciphertext
ciphertext_file = "23-ntru-example01-ciphertext.txt"
with open(ciphertext_file, "r") as f:
    text = f.read()

poly_str = text.split("=", _sage_const_1 )[_sage_const_1 ].strip()
c_poly = R(poly_str) % (x**N - _sage_const_1 )

# Find f and g
f_vec, g_vec = find_fg(vectors)
if f_vec is None:
    print("No suitable f found — check your LLL vectors or thresholds.")
    exit()

f = poly_from_vec(f_vec)
g = poly_from_vec(g_vec)

# Build ring elements
f_coeffs_q = [GF(q)(ZZ(c)) for c in f.list()] + [GF(q)(_sage_const_0 )] * (N - len(f.list()))
f_coeffs_p = [GF(p)(ZZ(c)) for c in f.list()] + [GF(p)(_sage_const_0 )] * (N - len(f.list()))

fq = Rq(f_coeffs_q)
fp = Rp(f_coeffs_p)

fq_inv = fq.inverse_mod(xq**N - _sage_const_1 )
fp_inv = fp.inverse_mod(xp**N - _sage_const_1 )

# Step 1: a = f * c mod (x^N - 1), center-lifted mod q
a_raw = (f * c_poly) % (x**N - _sage_const_1 )
a = center_lift(a_raw, q)

print("a (center-lifted):", a.list())

# Step 2: reduce a mod p, then multiply by f_p^{-1}
a_coeffs_p = [GF(p)(ZZ(c)) for c in a.list()] + [GF(p)(_sage_const_0 )] * (N - len(a.list()))
a_p = Rp(a_coeffs_p)

m = (fp_inv * a_p) % (xp**N - _sage_const_1 )

print("Decrypted message coefficients:", m.list())

